SELECT i.*, gif.gift_nm AS gift_nm, mem.member_nm AS member_nm, ord.member_nm AS order_nm, ste.site_nm AS site_nm, cd_gis.code_label AS gift_issue_status_cd_nm FROM pm_gift_issue i LEFT JOIN pm_gift gif ON gif.gift_id = i.gift_id LEFT JOIN mb_member mem ON mem.member_id = i.member_id LEFT JOIN od_order ord ON ord.order_id = i.order_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_gis ON cd_gis.code_grp = 'GIFT_ISSUE_STATUS' AND cd_gis.code_value = i.gift_issue_status_cd
ORDER BY i.gift_issue_id ASC ORDER BY i.gift_issue_id DESC ORDER BY i.issue_date ASC ORDER BY i.issue_date DESC ORDER BY i.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT i.*, gif.gift_nm AS gift_nm, mem.member_nm AS member_nm, ord.member_nm AS order_nm, ste.site_nm AS site_nm, cd_gis.code_label AS gift_issue_status_cd_nm FROM pm_gift_issue i LEFT JOIN pm_gift gif ON gif.gift_id = i.gift_id LEFT JOIN mb_member mem ON mem.member_id = i.member_id LEFT JOIN od_order ord ON ord.order_id = i.order_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_gis ON cd_gis.code_grp = 'GIFT_ISSUE_STATUS' AND cd_gis.code_value = i.gift_issue_status_cd
ORDER BY i.gift_issue_id ASC ORDER BY i.gift_issue_id DESC ORDER BY i.issue_date ASC ORDER BY i.issue_date DESC ORDER BY i.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

