UPDATE pm_gift_issue
gift_id = #{giftId}, site_id = #{siteId}, member_id = #{memberId}, order_id = #{orderId}, issue_date = #{issueDate}, gift_issue_status_cd = #{giftIssueStatusCd}, gift_issue_status_cd_before = #{giftIssueStatusCdBefore}, gift_issue_memo = #{giftIssueMemo}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE gift_issue_id = #{giftIssueId}
